INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (1, '立春偶成', '张栻', '宋', '律回岁晚冰霜少，春到人间草木知。便觉眼前生意满，东风吹水绿参差。', '冬天的寒冷逐渐消退，春天来临时，自然界的草木都能感受到。眼前顿时生机盎然，东风吹拂着水面，波光粼粼。', '这首诗是宋代诗人张栻创作的，表现了冬去春来的自然变化。诗人通过观察自然，感悟到春天的到来不仅改变了自然界，也给人们带来了新的希望。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_001-LaRnA3ykEsuKbXJhKFqg5A.webp', '节气', '春', '立春');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (2, '咏柳', '贺知章', '唐', '碧玉妆成一树高，万条垂下绿丝绦。不知细叶谁裁出，二月春风似剪刀。', '柳树像碧玉一样装扮成高高的树木，千万条柳条垂下来像绿色的丝带。不知道这细细的柳叶是谁裁剪出来的，就像二月的春风用剪刀剪出来一样。', '这是唐代诗人贺知章的名作，用拟人化的手法描写了春天柳树的美丽。整首诗充满了对春天的赞美和对生命活力的歌颂。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_002-jxceMa8ZUB7XutpTQouvRN.webp', '节气', '春', '立春');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (3, '春夜喜雨', '杜甫', '唐', '好雨知时节，当春乃发生。随风潜入夜，润物细无声。野径云俱黑，江船火独明。晓看红湿处，花重锦官城。', '春雨来得很及时，在春天时下起。它随着风悄悄地进入夜晚，润物无声。田野的小路被云笼罩得漆黑一片，只有江上的船火独自闪烁。天亮后看到被雨水浸湿的地方，花朵沉甸甸的，整个锦官城都被花香笼罩。', '这是杜甫最著名的诗作之一，创作于春雨时节。诗人以细腻的笔触描写了春雨的特点，表达了对春雨润物的赞美。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_003-5xkQ7ZxqRwYBcFztmu2pa8.webp', '节气', '春', '雨水');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (4, '绝句', '杜甫', '唐', '迟日江山丽，春风花草香。泥融飞燕子，沙暖睡鸳鸯。', '春天的日子变长了，江山显得格外秀丽，春风吹过花草散发出香气。泥土融化了，燕子开始飞翔，沙地变暖了，鸳鸯在这里安睡。', '这是杜甫的绝句之一，简洁而优美地描绘了春天的景象。每一句都是一幅生动的春日图画。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_004-9VENSQXbgVQfcBEa9vGhuF.webp', '节气', '春', '雨水');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (5, '观田家', '韦应物', '唐', '微雨众卉新，一雷惊蛰始。田家几日闲，耕种从此起。', '这是韦应物创作的诗作，描绘了春的景象。', '这首诗创作于唐代，由诗人韦应物创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_005-dvKQXrUcbVewsm7xWYt9en.webp', '节气', '春', '惊蛰');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (6, '新雷', '张维屏', '清', '造物无言却有情，每于寒尽觉春生。千红万紫安排著，只待新雷第一声。', '这是张维屏创作的诗作，描绘了春的景象。', '这首诗创作于清代，由诗人张维屏创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_006-hMgacdpucUnqhr3wrskZF4.webp', '节气', '春', '惊蛰');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (7, '春分日', '徐铉', '唐', '仲春初四日，春色正中分。绿野徘徊月，晴天断续云。燕飞犹个个，花落已纷纷。思妇高楼晚，歌声不可闻。', '这是徐铉创作的诗作，描绘了春的景象。', '这首诗创作于唐代，由诗人徐铉创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_007-NqZJDTupQVaVDKFgFkeXu9.webp', '节气', '春', '春分');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (8, '村居', '高鼎', '清', '草长莺飞二月天，拂堤杨柳醉春烟。儿童散学归来早，忙趁东风放纸鸢。', '这是高鼎创作的诗作，描绘了春的景象。', '这首诗创作于清代，由诗人高鼎创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_008-dcYsQzVn82S3LZaLABY29i.webp', '节气', '春', '春分');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (9, '清明', '杜牧', '唐', '清明时节雨纷纷，路上行人欲断魂。借问酒家何处有？牧童遥指杏花村。', '这是杜牧创作的诗作，描绘了春的景象。', '这首诗创作于唐代，由诗人杜牧创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_009-NmrBzJTzeUrCdntPGKVcBy.webp', '节气', '春', '清明');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (10, '寒食', '韩翃', '唐', '春城无处不飞花，寒食东风御柳斜。日暮汉宫传蜡烛，轻烟散入五侯家。', '这是韩翃创作的诗作，描绘了春的景象。', '这首诗创作于唐代，由诗人韩翃创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_010-ZMbKzegyJnBioK52x9iZHM.webp', '节气', '春', '清明');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (11, '晚春', '韩愈', '唐', '草树知春不久归，百般红紫斗芳菲。杨花榆荚无才思，惟解漫天作雪飞。', '这是韩愈创作的诗作，描绘了春的景象。', '这首诗创作于唐代，由诗人韩愈创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_011.webp', '节气', '春', '谷雨');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (12, '送春', '王令', '宋', '三月残花落更开，小檐日日燕飞来。子规夜半犹啼血，不信东风唤不回。', '这是王令创作的诗作，描绘了春的景象。', '这首诗创作于宋代，由诗人王令创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_012.webp', '节气', '春', '谷雨');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (13, '立夏', '陆游', '宋', '赤帜插城扉，东君整驾归。泥新巢燕闹，花尽蜜蜂稀。槐柳阴初密，帘栊暑尚微。日斜汤沐罢，熟练试单衣。', '这是陆游创作的诗作，描绘了夏的景象。', '这首诗创作于宋代，由诗人陆游创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_013.webp', '节气', '夏', '立夏');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (14, '池上', '白居易', '唐', '小娃撑小艇，偷采白莲回。不解藏踪迹，浮萍一道开。', '这是白居易创作的诗作，描绘了夏的景象。', '这首诗创作于唐代，由诗人白居易创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_014.webp', '节气', '夏', '立夏');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (15, '五绝·小满', '欧阳修', '宋', '夜莺啼绿柳，皓月醒长空。最爱垄头麦，迎风笑落红。', '这是欧阳修创作的诗作，描绘了夏的景象。', '这首诗创作于宋代，由诗人欧阳修创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_015.webp', '节气', '夏', '小满');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (16, '归田园四时乐春夏二首·其二', '欧阳修', '宋', '南风原头吹百草，草木丛深茅舍小。麦穗初齐稚子娇，桑叶正肥蚕食饱。', '这是欧阳修创作的诗作，描绘了夏的景象。', '这首诗创作于宋代，由诗人欧阳修创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_016.webp', '节气', '夏', '小满');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (17, '时雨', '陆游', '宋', '时雨及芒种，四野皆插秧。家家麦饭美，处处菱歌长。', '这是陆游创作的诗作，描绘了夏的景象。', '这首诗创作于宋代，由诗人陆游创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_017.webp', '节气', '夏', '芒种');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (18, '芒种', '窦常', '唐', '愿见纤纤擢素手，拾穗不违农时忙。', '这是窦常创作的诗作，描绘了夏的景象。', '这首诗创作于唐代，由诗人窦常创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_018.webp', '节气', '夏', '芒种');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (19, '晓出净慈寺送林子方', '杨万里', '宋', '毕竟西湖六月中，风光不与四时同。接天莲叶无穷碧，映日荷花别样红。', '这是杨万里创作的诗作，描绘了夏的景象。', '这首诗创作于宋代，由诗人杨万里创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_019.webp', '节气', '夏', '夏至');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (20, '夏至', '范成大', '宋', '李核垂腰祝饐，粽丝系臂扶羸。节物竞随乡俗，老翁闲伴儿嬉。', '这是范成大创作的诗作，描绘了夏的景象。', '这首诗创作于宋代，由诗人范成大创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_020.webp', '节气', '夏', '夏至');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (21, '小暑', '陆游', '宋', '万瓦鳞鳞若火龙，日车不动汗珠融。无因羽翮氛埃外，坐觉蒸炊釜甑中。', '这是陆游创作的诗作，描绘了夏的景象。', '这首诗创作于宋代，由诗人陆游创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_021.webp', '节气', '夏', '小暑');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (22, '夏日南亭怀辛大', '孟浩然', '唐', '山光忽西落，池月渐东上。散发乘夕凉，开轩卧闲敞。荷风送香气，竹露滴清响。', '这是孟浩然创作的诗作，描绘了夏的景象。', '这首诗创作于唐代，由诗人孟浩然创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_022.webp', '节气', '夏', '小暑');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (23, '大暑', '曾几', '宋', '赤日几时过，清风无处寻。经书聊枕籍，瓜李漫浮沉。兰若静复静，茅茨深又深。炎蒸乃如许，那更惜分阴。', '这是曾几创作的诗作，描绘了夏的景象。', '这首诗创作于宋代，由诗人曾几创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_023.webp', '节气', '夏', '大暑');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (24, '纳凉', '秦观', '宋', '携扙来追柳外凉，画桥南畔倚胡床。月明船笛参差起，风定池莲自在香。', '这是秦观创作的诗作，描绘了夏的景象。', '这首诗创作于宋代，由诗人秦观创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_024.webp', '节气', '夏', '大暑');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (25, '立秋', '刘翰', '唐', '睡起秋声无觅处，满阶梧叶月明中。', '这是刘翰创作的诗作，描绘了秋的景象。', '这首诗创作于唐代，由诗人刘翰创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_025.webp', '节气', '秋', '立秋');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (26, '山居秋暝', '王维', '唐', '空山新雨后，天气晚来秋。明月松间照，清泉石上流。竹喧归浣女，莲动下渔舟。随意春芳歇，王孙自可留。', '这是王维创作的诗作，描绘了秋的景象。', '这首诗创作于唐代，由诗人王维创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_026.webp', '节气', '秋', '立秋');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (27, '处暑', '苏泂', '宋', '处暑无三日，新凉直万金。白头更世事，青草印禅心。放鹤婆娑舞，听蛩断续吟。极知仁者寿，未必海之深。', '这是苏泂创作的诗作，描绘了秋的景象。', '这首诗创作于宋代，由诗人苏泂创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_027.webp', '节气', '秋', '处暑');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (28, '早秋', '许浑', '唐', '遥夜泛清瑟，西风生翠萝。残萤栖玉露，早雁拂金河。高树晓还密，远山晴更多。淮南一叶下，自觉洞庭波。', '这是许浑创作的诗作，描绘了秋的景象。', '这首诗创作于唐代，由诗人许浑创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_028.webp', '节气', '秋', '处暑');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (29, '月夜忆舍弟', '杜甫', '唐', '戍鼓断人行，边秋一雁声。露从今夜白，月是故乡明。有弟皆分散，无家问死生。寄书长不达，况乃未休兵。', '这是杜甫创作的诗作，描绘了秋的景象。', '这首诗创作于唐代，由诗人杜甫创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_029.webp', '节气', '秋', '白露');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (30, '秋词二首·其一', '刘禹锡', '唐', '自古逢秋悲寂寥，我言秋日胜春朝。晴空一鹤排云上，便引诗情到碧霄。', '这是刘禹锡创作的诗作，描绘了秋的景象。', '这首诗创作于唐代，由诗人刘禹锡创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_030.webp', '节气', '秋', '白露');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (31, '天净沙·秋思', '马致远', '元', '枯藤老树昏鸦，小桥流水人家，古道西风瘦马。夕阳西下，断肠人在天涯。', '这是马致远创作的诗作，描绘了秋的景象。', '这首诗创作于元代，由诗人马致远创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_031.webp', '节气', '秋', '秋分');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (32, '秋夕', '杜牧', '唐', '银烛秋光冷画屏，轻罗小扇扑流萤。天阶夜色凉如水，坐看牵牛织女星。', '这是杜牧创作的诗作，描绘了秋的景象。', '这首诗创作于唐代，由诗人杜牧创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_032.webp', '节气', '秋', '秋分');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (33, '寒露', '白居易', '唐', '袅袅凉风动，凄凄寒露零。兰衰花始白，荷破叶犹青。独立栖沙鹤，双飞照水萤。若为寥落境，仍值酒初醒。', '这是白居易创作的诗作，描绘了秋的景象。', '这首诗创作于唐代，由诗人白居易创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_033.webp', '节气', '秋', '寒露');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (34, '九月九日忆山东兄弟', '王维', '唐', '独在异乡为异客，每逢佳节倍思亲。遥知兄弟登高处，遍插茱萸少一人。', '这是王维创作的诗作，描绘了秋的景象。', '这首诗创作于唐代，由诗人王维创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_034.webp', '节气', '秋', '寒露');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (35, '山行', '杜牧', '唐', '远上寒山石径斜，白云生处有人家。停车坐爱枫林晚，霜叶红于二月花。', '这是杜牧创作的诗作，描绘了秋的景象。', '这首诗创作于唐代，由诗人杜牧创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_035.webp', '节气', '秋', '霜降');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (36, '霜月', '李商隐', '唐', '初闻征雁已无蝉，百尺楼高水接天。青女素娥俱耐冷，月中霜里斗婵娟。', '这是李商隐创作的诗作，描绘了秋的景象。', '这首诗创作于唐代，由诗人李商隐创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_036.webp', '节气', '秋', '霜降');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (37, '立冬', '李白', '唐', '冻笔新诗懒写，寒炉美酒时温。醉看墨花月白，恍疑雪满前村。', '这是李白创作的诗作，描绘了冬的景象。', '这首诗创作于唐代，由诗人李白创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_037.webp', '节气', '冬', '立冬');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (38, '江雪', '柳宗元', '唐', '千山鸟飞绝，万径人踪灭。孤舟蓑笠翁，独钓寒江雪。', '这是柳宗元创作的诗作，描绘了冬的景象。', '这首诗创作于唐代，由诗人柳宗元创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_038.webp', '节气', '冬', '立冬');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (39, '小雪', '戴叔伦', '唐', '花雪随风不厌看，更多还肯失林峦。愁人正在书窗下，一片飞来一片寒。', '这是戴叔伦创作的诗作，描绘了冬的景象。', '这首诗创作于唐代，由诗人戴叔伦创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_039.webp', '节气', '冬', '小雪');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (40, '夜雪', '白居易', '唐', '已讶衾枕冷，复见窗户明。夜深知雪重，时闻折竹声。', '这是白居易创作的诗作，描绘了冬的景象。', '这首诗创作于唐代，由诗人白居易创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_040.webp', '节气', '冬', '小雪');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (41, '大雪', '陆游', '宋', '大雪江南见未曾，今年方始是严凝。巧穿帘罅如相觅，重压林梢欲不胜。', '这是陆游创作的诗作，描绘了冬的景象。', '这首诗创作于宋代，由诗人陆游创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_041.webp', '节气', '冬', '大雪');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (42, '白雪歌送武判官归京', '岑参', '唐', '北风卷地白草折，胡天八月即飞雪。忽如一夜春风来，千树万树梨花开。', '这是岑参创作的诗作，描绘了冬的景象。', '这首诗创作于唐代，由诗人岑参创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_042.webp', '节气', '冬', '大雪');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (43, '冬至', '杜甫', '唐', '天时人事日相催，冬至阳生春又来。刺绣五纹添弱线，吹葭六琯动浮灰。岸容待腊将舒柳，山意冲寒欲放梅。云物不殊乡国异，教儿且覆掌中杯。', '这是杜甫创作的诗作，描绘了冬的景象。', '这首诗创作于唐代，由诗人杜甫创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_043.webp', '节气', '冬', '冬至');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (44, '邯郸冬至夜思家', '白居易', '唐', '邯郸驿里逢冬至，抱膝灯前影伴身。想得家中夜深坐，还应说着远行人。', '这是白居易创作的诗作，描绘了冬的景象。', '这首诗创作于唐代，由诗人白居易创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_044.webp', '节气', '冬', '冬至');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (45, '小寒', '陆游', '宋', '小寒已近手难舒，终日掩门深闭庐。树欲生寒叶将落，梅如解语亦情疏。', '这是陆游创作的诗作，描绘了冬的景象。', '这首诗创作于宋代，由诗人陆游创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_045.webp', '节气', '冬', '小寒');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (46, '梅花', '王安石', '宋', '墙角数枝梅，凌寒独自开。遥知不是雪，为有暗香来。', '这是王安石创作的诗作，描绘了冬的景象。', '这首诗创作于宋代，由诗人王安石创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_046.webp', '节气', '冬', '小寒');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (47, '大寒', '陆游', '宋', '大寒雪未消，闭户不能出。可怜切云冠，局此容膝室。', '这是陆游创作的诗作，描绘了冬的景象。', '这首诗创作于宋代，由诗人陆游创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_047.webp', '节气', '冬', '大寒');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (48, '卖炭翁', '白居易', '唐', '满面尘灰烟火色，两鬓苍苍十指黑。卖炭得钱何所营？身上衣裳口中食。可怜身上衣正单，心忧炭贱愿天寒。', '这是白居易创作的诗作，描绘了冬的景象。', '这首诗创作于唐代，由诗人白居易创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_048.webp', '节气', '冬', '大寒');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (49, '元日', '王安石', '宋', '爆竹声中一岁除，春风送暖入屠苏。千门万户曈曈日，总把新桃换旧符。', '这是王安石创作的诗作，描绘了季节的景象。', '这首诗创作于宋代，由诗人王安石创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_049.webp', '节日', '', '春节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (50, '拜年', '文徵明', '明', '不求见面惟通谒，名纸朝来满敝庐。我亦随人投数纸，世情嫌简不嫌虚。', '这是文徵明创作的诗作，描绘了季节的景象。', '这首诗创作于明代，由诗人文徵明创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_050.webp', '节日', '', '春节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (51, '守岁', '苏轼', '宋', '欲知垂尽岁，有似赴壑蛇。儿童强不睡，相守夜欢哗。', '这是苏轼创作的诗作，描绘了季节的景象。', '这首诗创作于宋代，由诗人苏轼创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_051.webp', '节日', '', '春节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (52, '新年作', '刘长卿', '唐', '乡心新岁切，天畔独潸然。老至居人下，春归在客先。岭猿同旦暮，江柳共风烟。已似长沙傅，从今又几年。', '这是刘长卿创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人刘长卿创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_052.webp', '节日', '', '春节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (53, '屠苏酒', '陆游', '宋', '半盏屠苏犹未举，灯前小草写桃符。', '这是陆游创作的诗作，描绘了季节的景象。', '这首诗创作于宋代，由诗人陆游创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_053.webp', '节日', '', '春节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (54, '迎春', '叶燮', '清', '律转鸿钧，新元肇启。东风解冻，淑气光临。', '这是叶燮创作的诗作，描绘了季节的景象。', '这首诗创作于清代，由诗人叶燮创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_054.webp', '节日', '', '春节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (55, '元夕', '辛弃疾', '宋', '东风夜放花千树，更吹落、星如雨。宝马雕车香满路。凤箫声动，玉壶光转，一夜鱼龙舞。蛾儿雪柳黄金缕，笑语盈盈暗香去。众里寻他千百度，蓦然回首，那人却在，灯火阑珊处。', '这是辛弃疾创作的诗作，描绘了季节的景象。', '这首诗创作于宋代，由诗人辛弃疾创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_055.webp', '节日', '', '元宵节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (56, '十五夜观灯', '卢照邻', '唐', '锦里开芳宴，兰缸艳早年。缛彩遥分地，繁光远缀天。接汉疑星落，依楼似月悬。别有千金笑，来映九枝前。', '这是卢照邻创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人卢照邻创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_056.webp', '节日', '', '元宵节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (57, '上元夜', '崔液', '唐', '玉漏银壶且莫催，铁关金锁彻明开。谁家见月能闲坐？何处闻灯不看来？', '这是崔液创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人崔液创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_057.webp', '节日', '', '元宵节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (58, '正月十五夜', '苏味道', '唐', '火树银花合，星桥铁锁开。暗尘随马去，明月逐人来。游伎皆秾李，行歌尽落梅。金吾不禁夜，玉漏莫相催。', '这是苏味道创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人苏味道创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_058.webp', '节日', '', '元宵节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (59, '元宵', '唐寅', '明', '有灯无月不娱人，有月无灯不算春。春到人间人似玉，灯烧月下月如银。', '这是唐寅创作的诗作，描绘了季节的景象。', '这首诗创作于明代，由诗人唐寅创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_059.webp', '节日', '', '元宵节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (60, '寒食', '韩翃', '唐', '春城无处不飞花，寒食东风御柳斜。日暮汉宫传蜡烛，轻烟散入五侯家。', '这是韩翃创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人韩翃创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_060.webp', '节日', '', '寒食节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (61, '寒食寄京师诸弟', '韦应物', '唐', '雨中禁火空斋冷，江上流莺独坐听。把酒看花想诸弟，杜陵寒食草青青。', '这是韦应物创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人韦应物创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_061.webp', '节日', '', '寒食节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (62, '寒食日即事', '温庭筠', '唐', '清溪一道穿桃李，演漾绿蒲涵白芷。溪上人家凡几家，落花半落东流水。蹴鞠屡过飞鸟上，秋千竞出垂杨里。少年分日作遨游，不用清明兼上巳。', '这是温庭筠创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人温庭筠创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_062.webp', '节日', '', '寒食节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (63, '清明', '王禹偁', '宋', '无花无酒过清明，兴味萧然似野僧。昨日邻家乞新火，晓窗分与读书灯。', '这是王禹偁创作的诗作，描绘了季节的景象。', '这首诗创作于宋代，由诗人王禹偁创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_063.webp', '节日', '', '清明节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (64, '苏堤清明即事', '吴惟信', '宋', '梨花风起正清明，游子寻春半出城。日暮笙歌收拾去，万株杨柳属流莺。', '这是吴惟信创作的诗作，描绘了季节的景象。', '这首诗创作于宋代，由诗人吴惟信创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_064.webp', '节日', '', '清明节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (65, '清明日', '温庭筠', '唐', '清娥画扇中，春树郁金红。出犯繁花露，归穿弱柳风。马骄偏避幰，鸡骇乍开笼。柘弹何人发，黄鹂隔故宫。', '这是温庭筠创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人温庭筠创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_065.webp', '节日', '', '清明节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (66, '端午', '文秀', '唐', '节分端午自谁言，万古传闻为屈原。堪笑楚江空渺渺，不能洗得直臣冤。', '这是文秀创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人文秀创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_066.webp', '节日', '', '端午节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (67, '竞渡诗', '卢肇', '唐', '石溪久住思端午，馆驿楼前看发机。鼙鼓动时雷隐隐，兽头凌处雪微微。冲波突出人齐譀，跃浪争先鸟退飞。向道是龙刚不信，果然夺得锦标归。', '这是卢肇创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人卢肇创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_067.webp', '节日', '', '端午节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (68, '乙卯重五诗', '陆游', '宋', '重五山村好，榴花忽已繁。粽包分两髻，艾束著危冠。旧俗方储药，羸躯亦点丹。日斜吾事毕，一笑向杯盘。', '这是陆游创作的诗作，描绘了季节的景象。', '这首诗创作于宋代，由诗人陆游创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_068.webp', '节日', '', '端午节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (69, '端午日', '殷尧藩', '唐', '少年佳节倍多情，老去谁知感慨生。不效艾符趋习俗，但祈蒲酒话升平。鬓丝日日添白头，榴锦年年照眼明。千载贤愚同瞬息，几人湮没几垂名。', '这是殷尧藩创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人殷尧藩创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_069.webp', '节日', '', '端午节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (70, '乞巧', '林杰', '唐', '七夕今宵看碧霄，牵牛织女渡河桥。家家乞巧望秋月，穿尽红丝几万条。', '这是林杰创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人林杰创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_070.webp', '节日', '', '七夕节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (71, '迢迢牵牛星', '佚名', '汉', '迢迢牵牛星，皎皎河汉女。纤纤擢素手，札札弄机杼。终日不成章，泣涕零如雨。河汉清且浅，相去复几许？盈盈一水间，脉脉不得语。', '这是佚名创作的诗作，描绘了季节的景象。', '这首诗创作于汉代，由诗人佚名创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_071.webp', '节日', '', '七夕节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (72, '七夕', '罗隐', '唐', '络角星河菡萏天，一家欢笑设红筵。应倾谢女珠玑箧，尽写檀郎锦绣篇。香帐簇成排窈窕，金针穿罢拜婵娟。铜壶漏报天将晓，惆怅佳期又一年。', '这是罗隐创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人罗隐创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_072.webp', '节日', '', '七夕节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (73, '十五夜望月', '王建', '唐', '中庭地白树栖鸦，冷露无声湿桂花。今夜月明人尽望，不知秋思落谁家。', '这是王建创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人王建创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_073.webp', '节日', '', '中秋节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (74, '水调歌头·明月几时有', '苏轼', '宋', '明月几时有？把酒问青天。不知天上宫阙，今夕是何年。我欲乘风归去，又恐琼楼玉宇，高处不胜寒。起舞弄清影，何似在人间。转朱阁，低绮户，照无眠。不应有恨，何事长向别时圆？人有悲欢离合，月有阴晴圆缺，此事古难全。但愿人长久，千里共婵娟。', '这是苏轼创作的诗作，描绘了季节的景象。', '这首诗创作于宋代，由诗人苏轼创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_074.webp', '节日', '', '中秋节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (75, '中秋月', '晏殊', '宋', '十轮霜影转庭梧，此夕羁人独向隅。未必素娥无怅恨，玉蟾清冷桂花孤。', '这是晏殊创作的诗作，描绘了季节的景象。', '这首诗创作于宋代，由诗人晏殊创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_075.webp', '节日', '', '中秋节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (76, '醉花阴·薄雾浓云愁永昼', '李清照', '宋', '薄雾浓云愁永昼，瑞脑销金兽。佳节又重阳，玉枕纱厨，半夜凉初透。东篱把酒黄昏后，有暗香盈袖。莫道不销魂，帘卷西风，人比黄花瘦。', '这是李清照创作的诗作，描绘了季节的景象。', '这首诗创作于宋代，由诗人李清照创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_076.webp', '节日', '', '重阳节');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (77, '除夜', '高适', '唐', '旅馆寒灯独不眠，客心何事转凄然。故乡今夜思千里，霜鬓明朝又一年。', '这是高适创作的诗作，描绘了季节的景象。', '这首诗创作于唐代，由诗人高适创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_077.webp', '节日', '', '除夕');
INSERT INTO poems (id, title, author, dynasty, content, translation, background, imageUrl, category, season, festival) 
VALUES (78, '除夜雪', '陆游', '宋', '北风吹雪四更初，嘉瑞天教及岁除。半盏屠苏犹未举，灯前小草写桃符。', '这是陆游创作的诗作，描绘了季节的景象。', '这首诗创作于宋代，由诗人陆游创作，表现了诗人对自然和生活的感悟。', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663445888686/ntSv2zsNtA9RfeuNrFJSEM/poem_078.webp', '节日', '', '除夕');